var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"여기가…… 소문의 그곳. 맞나요?","JPN":"ここが……あの噂の、ですね？","ENG":"Is this... where the rumors are all about?","TWN":"請問……這裡是傳說中的那個地方嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"마, 마담?!","JPN":"マ、マダム！？","ENG":"M-madam?!","TWN":"夫…夫人？！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"여긴 어떻게……!","JPN":"どうしてここに……！","ENG":"H-how did you...?!","TWN":"您怎麼會來……！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"소문을 듣고 찾아왔죠. 당신들이 악몽을 없애 준다는 그분들인가요?","JPN":"噂を聞いて来たのです。あなたたちが悪夢を消してくれるという方々ですか？","ENG":"I came after hearing all the rumors, of course. Are you the one who gets rid of nightmares?","TWN":"當然是因為聽到傳言，才找到這裡來的囉～你們就是可以幫人消除惡夢的人嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……저 누군지 모르세요?","JPN":"……私のこと、ご存じありませんか？","ENG":"...You don’t know who I am?","TWN":"……您不知道我是誰嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"정말…… 제가 누군지 모른다고요?","JPN":"本当に……私が誰なのか知らないんですか？","ENG":"Are you sure... you don’t know me?","TWN":"您真的……不認得我嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"미안해요. 나이가 드니 자꾸 깜빡하게 되네?","JPN":"ごめんなさいね。歳のせいか、うっかりしちゃうの。","ENG":"I’m sorry. Age has made my memories a little foggy.","TWN":"不好意思，上年紀後記性退步不少呢。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그럴 리가…….","JPN":"そんなわけ……","ENG":"No way...","TWN":"怎麼會……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그보다 여기.","JPN":"それより、はい。","ENG":"Anyway...","TWN":"話說，"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"얼만지는 얘기를 안 해주길래 넉넉히 챙겨 왔어요.","JPN":"いくらなのか教えてもらえなかったので、たっぷり持ってきました。","ENG":"No one told me what you charged, so I brought more than enough.","TWN":"我不知道這裡的收費，所以有多帶一點來。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"한…… 이 정도?","JPN":"そうね……このくらい？","ENG":"About... this much?","TWN":"差不多……這樣？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이, 이렇게나 많이요?!","JPN":"こ、こんなにですか！？","ENG":"Th-this much?!","TWN":"這…這麼多？！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"혹시 부족한가요? 더 챙겨 왔어야 됐나……?","JPN":"もしかして足りませんか？　もっと持ってくるべきだったかしら……？","ENG":"Is it not enough? Should I have brought more?","TWN":"夠嗎？還是要再多帶一點……？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……하, 하하! 아닙니다. 이 정도면 충분해요!","JPN":"……は、はは！　いいえ。これで十分ですよ！","ENG":"Hah... Hah hah! Not at all! This is more than enough!","TWN":"……哈哈哈！夠夠夠！非常夠！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"제가 아는 누구랑 너~무 닮으셔서 잠시 착각했나 봐요.","JPN":"私の知ってる人にあまりにも似てて、ちょっと勘違いしてしまったようです。","ENG":"You resemble someone I know, and I must’ve confused you for her.","TWN":"我剛好像認錯人，因為您長得和我認識的一個人很～像。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그래서 어떤 고민으로 오셨나요, 손님?","JPN":"それで、お悩みはなんですか？　お客様。","ENG":"So, what brings you here, ma’am?","TWN":"好的，這位客人，您有什麼煩惱嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"휴. 제가 요즘 통 잠을 못 자서…… 악몽에 깨는 일이 많거든요.","JPN":"ふぅ。この頃、どうしても眠れなくて……悪夢で目覚める時が多いのです。","ENG":"*Sigh...* I haven’t been able to get a good night’s rest... These nightmares keep waking me up, you see.","TWN":"哀，我最近都睡不好……老是從惡夢中驚醒過來。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"제가 맡은 일이 많기도 하고, 제게 의지하는 사람도 많고.","JPN":"担当している仕事も多いですし、私に頼る人もたくさんいるんです。","ENG":"I have many responsibilities, and many people rely on me.","TWN":"我要負責很多事，而且很多人都依賴我。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그래서 그런지 혼자 끙끙 앓다가 악몽을 꾸고 깨고 매일 반복이랍니다.","JPN":"だからか、一人で苦しんで悪夢を見ては目覚める毎日なのですよ。","ENG":"Perhaps that’s why I keep having these nightmares and waking up in the middle of the night.","TWN":"不知道是不是壓力太大，導致我每天都在做惡夢。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"저런……. 마담, 아니 손님도 악몽을 꾸셨군요.","JPN":"あらら……マダム、いや、お客様も悪夢を見てるんですね。","ENG":"Oh my... Madam- I mean, you’re also suffering from the nightmares.","TWN":"怎麼會……夫人，不對，這位客人，原來您也會做惡夢。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"정말 악몽을 없앨 수 있는 건가요?","JPN":"本当に悪夢を取り除くことができるのですか？","ENG":"Can you really get rid of these awful nightmares?","TWN":"你們真的有辦法消除惡夢嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그럼요! 우리 루루 님 전문이시랍니다.","JPN":"もちろんです！　ルル様の専門分野です。","ENG":"Leave it to us! Miss Lulu here is an expert in this field.","TWN":"那當然！我們露露老師可是專家！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그러기 위해선 먼저 잠드셔야 하는데…… 괜찮으시겠어요?","JPN":"そうするためにはまず眠る必要があるんですけど……大丈夫ですか？","ENG":"But in order to remove it, you first need to go to sleep. Is that okay with you?","TWN":"但在那之前，您必須先入睡……沒問題吧？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"당연하죠. 다만 제가 잠에 들려면 시간이 좀 걸려서…….","JPN":"もちろんです。ただ私が眠りにつくまで少し時間がかかるので……","ENG":"Not a problem. But it might take me some time to fall asleep...","TWN":"當然，只是我要花很長的時間才睡得著……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그건 걱정 마세요. 루루 님께서 푹 재워 주실 테니까요.","JPN":"それはご心配なく。ルル様がぐっすり寝かせてくださいますから。","ENG":"Oh, don’t worry about that. Miss Lulu will have you sleeping in no time.","TWN":"這您大可不必擔心，露露老師會幫助您入睡的。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그나저나 정말…… 주무셔도 괜찮으시겠어요?","JPN":"それより本当に……眠ってもいいのですか？","ENG":"But are you sure... you’re okay with sleeping?","TWN":"不過……在這裡睡著真的沒問題嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그럼요. 악몽만 없앨 수 있다면야 뭐든 하죠.","JPN":"当たり前です。悪夢さえ取り除くことができるのなら、何でもします。","ENG":"If it means getting rid of my nightmares, I’ll do anything.","TWN":"沒問題，只要能消除惡夢，要我做什麼都行。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"루루 님. 손님 부탁드릴게요.","JPN":"ルル様。お客様をお願いしますね。","ENG":"Miss Lulu, please help our customer.","TWN":"露露老師，客人就麻煩你囉。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"으음…… 정말 금방 졸려지네…….","JPN":"ううむ……本当にすぐ眠くなるのですね……","ENG":"Mm... I already feel like I’m about to fall asleep...","TWN":"嗯……真的很快就有睏的感覺……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"손님? 손님? ……헤론 님?","JPN":"お客様？　お客様？　……ヘロン様？","ENG":"Ma'am? Ma'am? M-madam Heron?","TWN":"客人？客人？……海倫夫人？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"잠들었어. 진짜 내가 누군지 못 알아보는 거야!","JPN":"寝ちゃった。本当に私が誰なのかわかんないんだよ！","ENG":"She actually dozed off. Does she really not know who I am?","TWN":"睡著了，她好像真的沒認出我來！"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"하긴, 위자드가 우리 같은 조무래기에 계속 신경 쓸 리 없지.","JPN":"まあ、ウィザードが私たちのような下っ端にずっと目を配るわけがないよね。","ENG":"But then again, it’s not like she’s gonna remember every grunt at Wizard.","TWN":"也是啦，像我們這種小咖，魔法師不可能一直花人力找我們吧？"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그러지 않고서야 우리 앞에서 이렇게 잠들 리가 없잖아?","JPN":"そうでもなけりゃ、私たちの前でこんな風に眠るわけないじゃん？","ENG":"Or, she wouldn’t have just started sleeping right in front of us.","TWN":"否則她也不可能在我們面前入睡吧？"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"……이 사람이 누군데?","JPN":"……この人、誰なの？","ENG":"Who is she?","TWN":"……她是誰？"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"헤이븐 형님 비서랄까. 아주 유능하신 분이셔.","JPN":"ヘイブン兄貴の秘書っていうか。とても有能な方だよ。","ENG":"She’s like the secretary for Mr. Haven. A very good one at that too.","TWN":"該說是天堂大哥的秘書嗎？是位非常能幹的女士。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"위저드에 종종 오셔서 아이들 머리 맡에서 자장가 불러 주시고, 다독여주시던 기억이 나.","JPN":"よくウィザードに来て、子供たちの枕元で子守歌を歌ってくれたり、あやしてくれたのを覚えてる。","ENG":"She used to visit Wizard and comfort the children by singing lullabies to them.","TWN":"我記得她常來魔法師，不只會唱搖籃曲給孩子們聽，還會安慰大家。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"그래……?","JPN":"ふうん……？","ENG":"Really...?","TWN":"是嗎……？"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"우리한테 친절하게 대해주는 사람이 그렇게 많지는 않았으니까.","JPN":"私たちに親切にしてくれる人はそんなに多くはなかったからなぁ。","ENG":"I remember her because not a lot of people were kind to us at Wizard.","TWN":"畢竟很少人會對我們那麼親切。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그나저나 일만 크레딧이라니!","JPN":"それより1万クレジットって！","ENG":"But giving us 10K credits?!","TWN":"不過有這麼多金幣欸！"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이 돈이면 장사도 접고 놀러 다녀도 돼!","JPN":"このお金なら、商売たたんで遊んでもいいくらいだよ！","ENG":"This is enough money to close shop and enjoy the rest of my life!","TWN":"有這麼多錢，我們乾脆把生意收起來去玩吧！"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"언제 붙잡힐지 모르니까, 헤론 님만 가시면 곧바로 여길 튀자.","JPN":"いつ捕まるかわからないから、ヘロン様さえ帰ったらすぐここから逃げよう。","ENG":"We don’t know when we’ll get caught, so let’s skip town right after removing her nightmare.","TWN":"也不知道什麼時候會被抓到，等海倫夫人離開後，我們就立刻跑路吧！"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"……이 사람. 왠지 익숙해.","JPN":"……この人。どこかでよく見た気がする。","ENG":"This person... Something feels familiar.","TWN":"總覺得她……有點眼熟。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"헤이븐 랜드랑 위저드랑 들락날락 했다며. 그때 마주쳤던가 그랬겠지, 뭐.","JPN":"ヘイブンランドとウィザードを行き来してたんでしょ？　その時出くわしたとか、そんなんじゃない？","ENG":"Didn’t you wander around Havenland and Wizard? I’m sure you bumped into her back then.","TWN":"你不是說你去過天堂樂園和魔法師嗎？應該是之前有遇到過吧？"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"그런가?","JPN":"そうかな？","ENG":"You think so?","TWN":"是嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"네가 악몽을 없애는 동안 내가 튈 준비해 둘게.","JPN":"アンタが悪夢を消してる間に、私が逃げる準備をしておくよ。","ENG":"While you get rid of her nightmare, I’ll start packing our stuff.","TWN":"趁你消除惡夢的時候，我去準備一下跑路的事。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"으응. 다녀올게.","JPN":"うん。行ってくるね。","ENG":"Okay. I’ll be back soon.","TWN":"嗯嗯，等下見。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};